     fn from(reason: &CancelReason) -> Self {
         Self {
             kind: CancelKindSnapshot::from(reason.kind()),
+            origin_region: reason.origin_region.into(),
+            origin_task: reason.origin_task.map(IdSnapshot::from),
+            timestamp: reason.timestamp.as_nanos(),
